import { useState, useEffect } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { Container, Row, Col, Card, Button, Alert, Spinner } from "react-bootstrap";
import api from "../services/api";  // Đảm bảo api.js đang dùng đúng endpoint

function PaymentPage() {
  const { orderId } = useParams();
  const navigate = useNavigate();
  const [order, setOrder] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");

  useEffect(() => {
    const fetchOrderDetails = async () => {
      try {
        setLoading(true);
        setError("");

        const response = await api.get(`/users/orders/${orderId}`, {
          headers: {
            Authorization: `Bearer ${localStorage.getItem('userToken')}`  // Lấy token từ localStorage
          }
        });

        if (response.data?.success && response.data?.data) {
          setOrder(response.data.data);
        } else {
          setError("Không tìm thấy thông tin đơn hàng");
        }
      } catch (err) {
        console.error("Lỗi khi tải thông tin đơn hàng:", err);
        setError("Có lỗi xảy ra khi tải thông tin đơn hàng");
      } finally {
        setLoading(false);
      }
    };

    fetchOrderDetails();
  }, [orderId]);

  const handlePayment = async () => {
    try {
      setError("");
      setSuccess("");

      // Gọi API thanh toán (Stripe, Blockchain, hoặc thanh toán thông qua hệ thống)
      const response = await api.post("/users/orders/pay", {
        order_id: orderId,
      }, {
        headers: {
          Authorization: `Bearer ${localStorage.getItem('userToken')}`  // Lấy token từ localStorage
        }
      });

      if (response.data?.success) {
        setSuccess("Thanh toán thành công! Đang chuyển đến trang xác nhận...");
        setTimeout(() => {
          navigate(`/order/${orderId}/confirmation`);
        }, 3000);
      } else {
        setError(response.data?.message || "Thanh toán không thành công");
      }
    } catch (err) {
      console.error("Lỗi khi thanh toán:", err);
      setError("Có lỗi xảy ra khi thanh toán");
    }
  };

  if (loading) {
    return (
      <div
        className="d-flex justify-content-center align-items-center"
        style={{ height: "100vh" }}
      >
        <Spinner animation="border" variant="primary" />
      </div>
    );
  }

  if (error) {
    return (
      <Container className="text-center mt-5">
        <Alert variant="danger">{error}</Alert>
      </Container>
    );
  }

  if (!order) {
    return (
      <Container className="text-center mt-5">
        <Alert variant="warning">Không tìm thấy thông tin đơn hàng này.</Alert>
      </Container>
    );
  }

  return (
    <Container className="my-5">
      <Row className="mb-4">
        <Col md={8}>
          <Card>
            <Card.Body>
              <Card.Title>Thông tin đơn hàng</Card.Title>
              <Card.Text>
                <strong>Ngày tạo:</strong> {new Date(order.created_at).toLocaleDateString("vi-VN")}
              </Card.Text>
              <Card.Text>
                <strong>Tổng số vé:</strong> {order.totalTickets}
              </Card.Text>
              <Card.Text>
                <strong>Tổng tiền:</strong>{" "}
                {Number(order.totalAmount).toLocaleString("vi-VN")} đ
              </Card.Text>
              <Card.Text>
                <strong>Trạng thái:</strong> {order.status}
              </Card.Text>
              <Button variant="success" onClick={handlePayment} disabled={order.status !== "awaiting_payment"}>
                Thanh toán
              </Button>
            </Card.Body>
          </Card>
        </Col>
      </Row>
    </Container>
  );
}

export default PaymentPage;
